"""
mkt-original layer — James chapter 5 (all 20 verses)
Output: data/commentary/mkt-original/james.json
Run: python3 scripts/zc-original-james-5-5-full.py

Interpretation decisions:
- 'the righteous person' (v6 ton dikaion): treated as a generic ethical reference
  to righteous poor, not a direct Christological title (though it echoes Acts 3:14; 7:52).
- 'end of the Lord' (v11 to telos kyriou): rendered as 'the Lord's own purpose/resolution,'
  not the Lord's death — fits the context of Job's vindication by God.
- Subject of 'will save' in v20: the intervenor, with God as ultimate agent —
  the verse credits the human act of restoration while pointing to divine mercy.
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {
  "5": {
    "1": "<p><strong>ἄγε νῦν, οἱ πλούσιοι, κλαύσατε ὀλολύζοντες</strong> — <em>ἄγε νῦν</em> (come now) is James's rhetorical address marker (cf. 4:13) that introduces a prophetic indictment. <em>κλαύσατε</em> (weep, aorist imperative) pairs with the participle <em>ὀλολύζοντες</em> (wailing/howling) — the second verb occurs in the LXX prophets specifically for eschatological lamentation over judgment coming on the wicked (Isa 13:6; 14:31; 15:3; 23:1); James appropriates the prophetic genre directly. <em>ταλαιπωρίαις</em> (miseries) is hapax in the NT; the plural form intensifies the completeness of the coming suffering.</p>",
    "2": "<p><strong>ὁ πλοῦτος ὑμῶν σέσηπεν, καὶ τὰ ἱμάτια ὑμῶν σητόβρωτα γέγονεν</strong> — both verbs are perfect tense: <em>σέσηπεν</em> (has rotted, from <em>σήπω</em>) and <em>γέγονεν</em> (has become). The perfects describe a completed state of decay that is prophetically proleptical — James speaks of future judgment as though already accomplished, a device common in OT prophecy (cf. Isa 40:1-2, where Babylon's fall is spoken as past). <em>σητόβρωτα</em> (moth-eaten) is a compound adjective; garments and stored grain/food represent the two primary forms of pre-monetary wealth storage in agrarian Palestinian society.</p>",
    "3": "<p><strong>ὁ χρυσὸς ὑμῶν καὶ ὁ ἄργυρος κατίωται</strong> — <em>κατίωται</em> (has corroded/rusted, from <em>κατιόομαι</em>) is technically inaccurate (gold and silver do not rust), which is precisely the rhetorical point: the improbable corrosion of precious metals signals the completeness of the coming judgment. <em>εἰς μαρτύριον ὑμῖν ἔσται</em> (it will be as testimony against you) — the corroded wealth becomes a legal witness in the divine court. <em>φάγεται τὰς σάρκας ὑμῶν ὡς πῦρ</em> (will eat your flesh like fire) — the devouring imagery echoes the consuming fire of Mal 4:1 and Isa 10:16-17.</p>",
    "4": "<p><strong>ἰδοὺ ὁ μισθὸς τῶν ἐργατῶν... ὁ ἀπεστερημένος ἀφ' ὑμῶν κράζει</strong> — <em>ἀπεστερημένος</em> (defrauded, perfect passive participle) echoes the Septuagintal language of Lev 19:13 (<em>οὐ μὴ ἀποστερήσεις</em>) and Deut 24:14-15, the Mosaic law protecting day laborers' wages. The withheld wages <em>κράζουσιν</em> (cry out) — the same verb as Abel's blood crying out from the ground (Gen 4:10 LXX: <em>φωνὴ αἵματος... βοᾷ</em>). The divine title <strong>κύριος σαβαώθ</strong> (Lord of Hosts/Sabaoth) is the only occurrence in the NT; by using the Hebrew transliteration rather than the Greek equivalent (<em>κύριος παντοκράτωρ</em>), James evokes the specifically prophetic tradition — the battle-Lord who vindicates the oppressed.</p>",
    "5": "<p><strong>ἐτρυφήσατε ἐπὶ τῆς γῆς καὶ ἐσπαταλήσατε</strong> — the two aorists describe completed patterns of self-indulgence: <em>τρυφάω</em> (to live luxuriously, in soft indulgence) and <em>σπαταλάω</em> (to live wantonly/wastefully — the same verb used of the prodigal son in 1 Tim 5:6 for widows who 'live for pleasure'). <em>ἐθρέψατε τὰς καρδίας ὑμῶν ἐν ἡμέρᾳ σφαγῆς</em> (you have fattened your hearts in a day of slaughter) — the image of livestock fattened for the day they will be killed is drawn from Jer 12:3 LXX (<em>ἁγίασον αὐτοὺς εἰς ἡμέραν σφαγῆς αὐτῶν</em>); the rich who fatten themselves are unwittingly preparing themselves for divine slaughter.</p>",
    "6": "<p><strong>κατεδικάσατε, ἐφονεύσατε τὸν δίκαιον</strong> — the judicial chain: <em>κατεδικάσατε</em> (you condemned, legal sentence) followed by <em>ἐφονεύσατε</em> (you murdered, execution of that sentence). <em>τὸν δίκαιον</em> (the righteous one) — the definite article with the singular may indicate a specific individual or function as a collective: 'the righteous person [characteristically].' Patristic readers saw an allusion to Christ (cf. Acts 3:14; 7:52 where Stephen uses the same title of Jesus), but the collective reading (the poor and righteous who are systematically oppressed) fits the social-justice argument James has been making. <em>οὐκ ἀντιτάσσεται ὑμῖν</em> (does not resist you) — the passive non-resistance of the righteous victim intensifies the moral culpability of the perpetrators.</p>",
    "7": "<p><strong>μακροθυμήσατε οὖν, ἀδελφοί, ἕως τῆς παρουσίας τοῦ κυρίου</strong> — James shifts from prophetic indictment of the rich to direct pastoral address to the community. <em>μακροθυμία</em> (long-suffering, patience-toward-persons — as distinct from <em>ὑπομονή</em>, endurance of circumstances) is the quality of not retaliating or despairing when people treat you unjustly. <em>παρουσία</em> (coming, arrival — the standard NT eschatological term for the Lord's return) is James's sole use of the term; the agricultural illustration: <em>ἐκδέχεται</em> (eagerly awaits) + <em>πρόϊμον καὶ ὄψιμον</em> (early and late rain — the October-November planting rains and the March-April pre-harvest rains of Palestine, cf. Deut 11:14; Joel 2:23) — the farmer's patient waiting for the climatically necessary rains models the community's active, hope-grounded waiting for the parousia.</p>",
    "8": "<p><strong>μακροθυμήσατε καὶ ὑμεῖς, στηρίξατε τὰς καρδίας ὑμῶν, ὅτι ἡ παρουσία τοῦ κυρίου ἤγγικεν</strong> — <em>στηρίξατε τὰς καρδίας</em> (strengthen your hearts) — the same verb Paul uses in 1 Thess 3:13 ('establish your hearts unblameable in holiness') and Luke 22:32 ('strengthen your brothers'). <em>ἤγγικεν</em> (has drawn near, perfect of <em>ἐγγίζω</em>) — the same verb Jesus used to announce the kingdom's arrival (Mark 1:15; Matt 4:17); the perfect tense indicates a present state resulting from a past movement: the parousia has come near and remains near. This nearness is the theological foundation for James's pastoral ethics throughout the letter.</p>",
    "9": "<p><strong>μὴ στενάζετε κατ' ἀλλήλων, ἀδελφοί, ἵνα μὴ κριθῆτε</strong> — <em>στενάζετε</em> (groan, sigh — the present imperative prohibition) covers not just verbal complaint but the internal disposition of resentment and mutual grievance that pressure produces in a community. The prohibition is grounded eschatologically: <em>ἵνα μὴ κριθῆτε</em> (so that you will not be judged). <em>ὁ κριτὴς πρὸ τῶν θυρῶν ἕστηκεν</em> (the Judge stands before the doors) — the same vivid spatial metaphor as Rev 3:20 (<em>ἰδοὺ ἕστηκα ἐπὶ τὴν θύραν</em>); the Judge standing at the threshold makes the eschatological boundary between 'now' and 'judgment' spatially present rather than temporally distant.</p>",
    "10": "<p><strong>ὑπόδειγμα λάβετε, ἀδελφοί, τῆς κακοπαθίας καὶ τῆς μακροθυμίας τοὺς προφήτας</strong> — <em>ὑπόδειγμα</em> (example, model for imitation — as distinct from <em>τύπος</em> which carries typological/representative force) presents the prophets as directly imitable examples rather than typological prefigurations. <em>κακοπαθίας</em> (suffering, hardship-endurance) is paired with <em>μακροθυμίας</em> (patient endurance toward difficult persons) — the same pairing James used in v. 7 for the farmer. <em>τοὺς λαλήσαντας ἐν τῷ ὀνόματι κυρίου</em> (those who spoke in the name of the Lord) — speaking in the Lord's name is precisely what made the prophets targets: Jeremiah, Amos, Isaiah all suffered for their authoritative proclamation.</p>",
    "11": "<p><strong>ἰδοὺ μακαρίζομεν τοὺς ὑπομείναντας· τὴν ὑπομονὴν Ἰὼβ ἠκούσατε</strong> — James shifts from <em>μακροθυμία</em> to <em>ὑπομονή</em> (endurance of circumstances) in characterizing Job — a subtle distinction: Job's test was not primarily against difficult persons but against catastrophic loss. <em>μακαρίζομεν</em> (we call blessed, present tense — a community practice of beatitude-declaration). <em>τὸ τέλος κυρίου εἴδετε</em> — 'the Lord's <em>telos</em>' is ambiguous: either God's final purpose/resolution (the restoration of Job in chs. 42) or the outcome God brought about for Job. <em>πολύσπλαγχνός ἐστιν ὁ κύριος καὶ οἰκτίρμων</em> — <em>πολύσπλαγχνος</em> (very compassionate, rich in compassion) is a NT hapax and LXX hapax; <em>οἰκτίρμων</em> derives from the classic OT divine character formula (Exod 34:6 LXX: <em>οἰκτίρμων καὶ ἐλεήμων</em>).</p>",
    "12": "<p><strong>πρὸ πάντων δέ, ἀδελφοί μου, μὴ ὀμνύετε</strong> — <em>πρὸ πάντων</em> (above all, before everything) — this emphatic marker indicates the special gravity of the oath prohibition; it is not a new topic but the capstone of the patience-endurance section: community members under pressure are tempted to invoke oaths to give weight to their complaints. <em>μὴ ὀμνύετε μήτε τὸν οὐρανὸν μήτε τὴν γῆν μήτε ἄλλον τινὰ ὅρκον</em> (do not swear by heaven or earth or any other oath) — this broadens even Jesus's formulation in Matt 5:34-36, which specifies particular forbidden oath-objects; James prohibits all oath-invocation. <em>ἤτω δὲ ὑμῶν τὸ ναὶ ναὶ καὶ τὸ οὒ οὔ</em> (let your yes be yes and your no be no) — the repeated single affirmations (<em>ναὶ ναί</em>, <em>οὒ οὔ</em>) indicate unambiguous simplicity, not doubling-up as an oath substitute.</p>",
    "13": "<p><strong>κακοπαθεῖ τις ἐν ὑμῖν; προσευχέσθω· εὐθυμεῖ τις; ψαλλέτω</strong> — the three-question structure of vv. 13-14 covers the experiential range of community life: <em>κακοπαθεῖ</em> (is suffering/undergoing hardship — the same root as v. 10's <em>κακοπαθίας</em>); <em>εὐθυμεῖ</em> (is in good cheer/cheerful — the same root as Acts 27:22, 25 where Paul encourages the sailors). The response to suffering is <em>προσευχέσθω</em> (let him pray, present imperative — continuous prayer); the response to cheerfulness is <em>ψαλλέτω</em> (let him sing psalms/praise, present imperative) — both responses are communally visible and orient the individual's state toward God.</p>",
    "14": "<p><strong>ἀσθενεῖ τις ἐν ὑμῖν; προσκαλεσάσθω τοὺς πρεσβυτέρους τῆς ἐκκλησίας</strong> — <em>ἀσθενεῖ</em> (is sick/weak) encompasses both physical illness and the weakened condition that illness produces in relation to God and community. The sick person is to <em>call</em> the elders — the initiative lies with the sick person, not passively waiting for pastoral visit. <em>τοὺς πρεσβυτέρους τῆς ἐκκλησίας</em> (the elders of the church) — the plural indicates this is a communal act, not an individual rite; James presupposes an established church structure. <em>ἀλείψαντες αὐτὸν ἐλαίῳ ἐν τῷ ὀνόματι τοῦ κυρίου</em> — <em>ἀλείψαντες</em> (anointing, aorist participle) rather than <em>χρίσαντες</em> (anointing with ritual/ceremonial connotation); oil was a standard Greco-Roman and Jewish medical treatment (cf. Luke 10:34), but <em>ἐν τῷ ὀνόματι</em> (in the name of the Lord) locates the efficacy in the Lord's authority, not the medical application.</p>",
    "15": "<p><strong>ἡ εὐχὴ τῆς πίστεως σώσει τὸν κάμνοντα</strong> — <em>εὐχὴ τῆς πίστεως</em> (the prayer of faith, genitive of quality) — faith characterizes the prayer, not the sick person or the elders specifically; the prayer is trust-saturated and directed to the Lord whose name was invoked in the anointing (v. 14). <em>σώσει</em> (will save, future) — <em>σῴζω</em> covers both physical restoration and spiritual salvation; James likely intends both registers given the added clause about sin-forgiveness. <em>ἐγερεῖ αὐτὸν ὁ κύριος</em> (the Lord will raise him up) — <em>ἐγείρω</em> is the standard NT resurrection verb; its use here for physical recovery carries eschatological overtones. <em>κἂν ἁμαρτίας ᾖ πεποιηκώς, ἀφεθήσεται αὐτῷ</em> (even if he has committed sins, they will be forgiven him) — divine passive; the connection of illness and sin is not causal (contra a mechanistic health-and-wealth theology) but pastoral: the whole person — body and soul — is addressed in the rite.</p>",
    "16": "<p><strong>ἐξομολογεῖσθε οὖν ἀλλήλοις τὰς ἁμαρτίας καὶ εὔχεσθε ὑπὲρ ἀλλήλων</strong> — the mutual structure is emphatic: <em>ἀλλήλοις</em> (to one another) and <em>ὑπὲρ ἀλλήλων</em> (for one another) — this is not auricular confession to a priest but reciprocal community confession and intercession. <em>ὅπως ἰαθῆτε</em> (so that you may be healed) — <em>ἰάομαι</em> is the standard healing verb, broader than just physical recovery. <em>πολὺ ἰσχύει δέησις δικαίου ἐνεργουμένη</em> — the grammar is contested: <em>ἐνεργουμένη</em> (being-energized) could be middle (prayer that is energized/operative) or passive (prayer that is set in motion by the Spirit); most interpreters take it as middle — 'the prayer of a righteous person, as it operates/in its working, is very powerful.'</p>",
    "17": "<p><strong>Ἠλίας ἄνθρωπος ἦν ὁμοιοπαθὴς ἡμῖν</strong> — <em>ὁμοιοπαθής</em> (of like passions/nature — sharing the same susceptibilities as us) appears only here and Acts 14:15 in the NT; in Acts, Paul and Barnabas use it to deny their own divinity. James uses it to establish the full humanity of Elijah and therefore the relevance of his prayer as a model: his effectiveness in prayer is not due to some superhuman quality but to his righteousness (v. 16) and earnestness. <em>καὶ προσευχῇ προσηύξατο</em> (and he prayed with prayer — a Hebraism, intensifying the earnestness) — cf. 1 Kgs 17:1 (Elijah's prayer for drought) and 1 Kgs 18:42-45 (the prayer for rain), both involving physical posture (1 Kgs 18:42: he bowed himself down on the earth and put his face between his knees).</p>",
    "18": "<p><strong>καὶ πάλιν προσηύξατο, καὶ ὁ οὐρανὸς ὑετὸν ἔδωκεν καὶ ἡ γῆ ἐβλάστησεν τὸν καρπὸν αὐτῆς</strong> — the brevity of the verse maps the structure of Elijah's prayer over seven petitions in 1 Kgs 18:43-44 (the servant was sent seven times to look toward the sea before the cloud appeared). The cosmic scale of the answer — heaven gives rain, the earth brings forth her fruit — frames intercessory prayer as a participation in the ordering of creation. James's two examples (the drought and the rain) bracket the full range of prophetic intercession: both withholding and restoring the created order's blessing are within the scope of righteous prayer.</p>",
    "19": "<p><strong>Ἀδελφοί μου, ἐάν τις ἐν ὑμῖν πλανηθῇ ἀπὸ τῆς ἀληθείας καὶ ἐπιστρέψῃ τις αὐτόν</strong> — the final pericope pivots from prayer for the sick to the ministry of doctrinal/ethical restoration. <em>πλανηθῇ ἀπὸ τῆς ἀληθείας</em> (stray from the truth, aorist passive subjunctive — the passive suggesting that wandering is something that happens to a person, not necessarily chosen deliberately) — <em>ἀλήθεια</em> in James encompasses both right belief and right conduct (1:18: 'he chose to give us birth through the word of truth'; 3:14: do not boast and lie against the truth). <em>ἐπιστρέψῃ τις αὐτόν</em> (someone turns him back) — <em>ἐπιστρέφω</em> is the standard LXX and NT verb for repentance as 'turning' (Isa 6:10; Acts 3:19; Luke 1:16-17).</p>",
    "20": "<p><strong>γινωσκέτω ὅτι ὁ ἐπιστρέψας ἁμαρτωλὸν ἐκ πλάνης ὁδοῦ αὐτοῦ σώσει ψυχὴν ἐκ θανάτου καὶ καλύψει πλῆθος ἁμαρτιῶν</strong> — <em>σώσει ψυχὴν ἐκ θανάτου</em> (will save a soul from death) — the subject is ambiguous: is it the intervenor who saves, or God through the intervenor? The Greek allows both; the agency of restoration points ultimately to divine mercy while crediting the human act. <em>καλύψει πλῆθος ἁμαρτιῶν</em> (will cover a multitude of sins) — from Prov 10:12 LXX (<em>πάντας δὲ τοὺς μὴ φιλονεικοῦντας καλύπτει φιλία</em>); 1 Pet 4:8 cites the same maxim. The whose sins are covered is debated — the wanderer's (the restored person) or the restorer's (as a merit earned). The most natural reading: the sins of the wanderer are covered through their restoration. The letter ends not with a doxology but with a human act of mercy — characteristically Jacobean in its fusion of faith and works.</p>"
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-original', 'james')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-original', 'james', existing)
    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / 'james.json'))
    all_ok = True
    for ch in ['5']:
        missing = set(il.get(ch, {}).keys()) - set(existing.get(ch, {}).keys())
        if missing:
            print(f'  ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch {ch}: complete ({len(existing.get(ch, {}))} verses)')
    if all_ok:
        print('All verses present')
